import{_ as e,o as a,c as l,a2 as r}from"./chunks/framework.BQ1gajhD.js";const f=JSON.parse('{"title":"中国国家博物馆历史","description":"","frontmatter":{},"headers":[],"relativePath":"history/national-museum.md","filePath":"history/national-museum.md","lastUpdated":1784769838000}'),d={name:"history/national-museum.md"};function n(i,t,s,o,h,g){return a(),l("div",null,[...t[0]||(t[0]=[r('<h1 id="中国国家博物馆历史" tabindex="-1">中国国家博物馆历史 <a class="header-anchor" href="#中国国家博物馆历史" aria-label="Permalink to &quot;中国国家博物馆历史&quot;">​</a></h1><div class="tip custom-block"><p class="custom-block-title">📖 完整导览</p><p>本页为<strong>历史沿革视角</strong>。国博完整导览（含常设展览、镇馆之宝详解）请见 → <a href="/beijing-travel-guide/museums/national-museum.html">中国国家博物馆</a></p></div><p><img src="https://images.unsplash.com/photo-1701847895783-979e086dae5e?w=1200" alt="中国国家博物馆"></p><blockquote><p>&quot;中华文明的殿堂，民族记忆的宝库。&quot;</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>中国国家博物馆位于天安门广场东侧，是世界上建筑面积最大的博物馆，也是中国最高历史文化艺术殿堂。馆藏文物超过140万件，系统展示了中国从远古到近现代的历史发展进程。</p><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>开放时间</strong></td><td style="text-align:left;">9:00-17:00（周一闭馆）</td></tr><tr><td style="text-align:left;"><strong>门票价格</strong></td><td style="text-align:left;">免费（需预约）</td></tr><tr><td style="text-align:left;"><strong>建议游玩</strong></td><td style="text-align:left;">3-4小时至一天</td></tr><tr><td style="text-align:left;"><strong>交通方式</strong></td><td style="text-align:left;">地铁1号线天安门东站</td></tr><tr><td style="text-align:left;"><strong>预约方式</strong></td><td style="text-align:left;">国博官网、微信公众号</td></tr></tbody></table><h2 id="历史沿革" tabindex="-1">历史沿革 <a class="header-anchor" href="#历史沿革" aria-label="Permalink to &quot;历史沿革&quot;">​</a></h2><h3 id="前身溯源" tabindex="-1">前身溯源 <a class="header-anchor" href="#前身溯源" aria-label="Permalink to &quot;前身溯源&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">时间</th><th style="text-align:left;">事件</th></tr></thead><tbody><tr><td style="text-align:left;">1912年</td><td style="text-align:left;">国立历史博物馆筹备处成立</td></tr><tr><td style="text-align:left;">1926年</td><td style="text-align:left;">正式开馆，馆址在故宫的午门和端门</td></tr><tr><td style="text-align:left;">1949年</td><td style="text-align:left;">新中国成立后更名为中国历史博物馆</td></tr><tr><td style="text-align:left;">1959年</td><td style="text-align:left;">迁入新馆（现址）</td></tr><tr><td style="text-align:left;">2003年</td><td style="text-align:left;">中国历史博物馆和中国革命博物馆合并组建中国国家博物馆</td></tr><tr><td style="text-align:left;">2011年</td><td style="text-align:left;">新馆建成开放</td></tr></tbody></table><h3 id="中国革命博物馆" tabindex="-1">中国革命博物馆 <a class="header-anchor" href="#中国革命博物馆" aria-label="Permalink to &quot;中国革命博物馆&quot;">​</a></h3><p>中国革命博物馆的前身是1950年成立的中央革命博物馆筹备处，主要收藏中国共产党领导中国革命的历史文物。</p><h3 id="两馆合并" tabindex="-1">两馆合并 <a class="header-anchor" href="#两馆合并" aria-label="Permalink to &quot;两馆合并&quot;">​</a></h3><p>2003年2月28日，中国历史博物馆和中国革命博物馆合并组建中国国家博物馆。</p><h3 id="改扩建工程" tabindex="-1">改扩建工程 <a class="header-anchor" href="#改扩建工程" aria-label="Permalink to &quot;改扩建工程&quot;">​</a></h3><p>2007年至2011年，国博进行了历时近4年的改扩建工程。新馆建筑面积近20万平方米，展厅面积6.5万平方米，成为世界上单体建筑面积最大的博物馆。</p><h2 id="镇馆之宝" tabindex="-1">镇馆之宝 <a class="header-anchor" href="#镇馆之宝" aria-label="Permalink to &quot;镇馆之宝&quot;">​</a></h2><h3 id="后母戊鼎" tabindex="-1">后母戊鼎 <a class="header-anchor" href="#后母戊鼎" aria-label="Permalink to &quot;后母戊鼎&quot;">​</a></h3><p>商代后期铸造，是世界现存最大、最重的青铜器，重达832.84公斤。</p><p><img src="https://images.unsplash.com/photo-1566127444979-b3d2b654e3d7?w=800" alt="后母戊鼎"></p><h3 id="四羊方尊" tabindex="-1">四羊方尊 <a class="header-anchor" href="#四羊方尊" aria-label="Permalink to &quot;四羊方尊&quot;">​</a></h3><p>商代晚期青铜礼器，尊身四角各塑一羊，被誉为&quot;臻于极致的青铜典范&quot;。</p><h3 id="金缕玉衣" tabindex="-1">金缕玉衣 <a class="header-anchor" href="#金缕玉衣" aria-label="Permalink to &quot;金缕玉衣&quot;">​</a></h3><p>西汉时期的帝王葬服，用2008片玉片以金丝编缀而成，全长1.88米。</p><h2 id="文化故事" tabindex="-1">文化故事 <a class="header-anchor" href="#文化故事" aria-label="Permalink to &quot;文化故事&quot;">​</a></h2><h3 id="后母戊鼎的故事" tabindex="-1">后母戊鼎的故事 <a class="header-anchor" href="#后母戊鼎的故事" aria-label="Permalink to &quot;后母戊鼎的故事&quot;">​</a></h3><p>后母戊鼎1939年出土于河南安阳，当时正值抗日战争时期。当地村民为保护国宝，将其重新埋藏，直至抗战胜利后才取出。</p><h2 id="游览攻略" tabindex="-1">游览攻略 <a class="header-anchor" href="#游览攻略" aria-label="Permalink to &quot;游览攻略&quot;">​</a></h2><h3 id="推荐参观路线" tabindex="-1">推荐参观路线 <a class="header-anchor" href="#推荐参观路线" aria-label="Permalink to &quot;推荐参观路线&quot;">​</a></h3><p><strong>半日游（精华路线）</strong>： 古代中国展厅 → 后母戊鼎 → 四羊方尊 → 金缕玉衣 → 复兴之路展厅 → 开国大典 → 神舟飞船</p><h3 id="预约须知" tabindex="-1">预约须知 <a class="header-anchor" href="#预约须知" aria-label="Permalink to &quot;预约须知&quot;">​</a></h3><ol><li><strong>提前预约</strong>：必须提前在国博官网、微信公众号或APP预约</li><li><strong>实名预约</strong>：需提供身份证信息</li><li><strong>周一闭馆</strong>：法定节假日除外</li></ol><h3 id="必看清单" tabindex="-1">必看清单 <a class="header-anchor" href="#必看清单" aria-label="Permalink to &quot;必看清单&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">文物</th><th style="text-align:left;">看点</th></tr></thead><tbody><tr><td style="text-align:left;">后母戊鼎</td><td style="text-align:left;">世界最大青铜器</td></tr><tr><td style="text-align:left;">四羊方尊</td><td style="text-align:left;">青铜器精品</td></tr><tr><td style="text-align:left;">金缕玉衣</td><td style="text-align:left;">帝王葬服</td></tr><tr><td style="text-align:left;">开国大典油画</td><td style="text-align:left;">新中国诞生</td></tr><tr><td style="text-align:left;">神舟返回舱</td><td style="text-align:left;">航天成就</td></tr></tbody></table><h2 id="交通指南" tabindex="-1">交通指南 <a class="header-anchor" href="#交通指南" aria-label="Permalink to &quot;交通指南&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">方式</th><th style="text-align:left;">路线</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>地铁</strong></td><td style="text-align:left;">1号线天安门东站D口，直接进馆</td></tr><tr><td style="text-align:left;"><strong>公交</strong></td><td style="text-align:left;">1、2、52、82路天安门东站</td></tr></tbody></table><h2 id="周边景点" tabindex="-1">周边景点 <a class="header-anchor" href="#周边景点" aria-label="Permalink to &quot;周边景点&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">景点</th><th style="text-align:center;">距离</th></tr></thead><tbody><tr><td style="text-align:left;">天安门广场</td><td style="text-align:center;">0米</td></tr><tr><td style="text-align:left;">天安门城楼</td><td style="text-align:center;">200米</td></tr><tr><td style="text-align:left;">故宫</td><td style="text-align:center;">500米</td></tr><tr><td style="text-align:left;">人民大会堂</td><td style="text-align:center;">300米</td></tr></tbody></table><hr><p><strong>💡 Tips</strong>：中国国家博物馆是了解中华文明的必去之地。建议预留充足时间，慢慢欣赏这些承载着五千年历史的珍贵文物。</p>',41)])])}const b=e(d,[["render",n]]);export{f as __pageData,b as default};
